    fn poll_write(
        self: Pin<&mut Self>,
        cx: &mut Context<'_>,
        buf: &[u8],
    ) -> Poll<io::Result<usize>>;

    fn poll_flush(...) -> Poll<io::Result<()>>;
    fn poll_shutdown(...) -> Poll<io::Result<()>>;
}
```

### AsyncBufRead
```rust
pub trait AsyncBufRead: AsyncRead {
    fn poll_fill_buf(...) -> Poll<io::Result<&[u8]>>;
    fn consume(self: Pin<&mut Self>, amt: usize);
}
```

### AsyncSeek
```rust
pub trait AsyncSeek {
    fn poll_seek(..., pos: SeekFrom) -> Poll<io::Result<u64>>;
}
```

