```rust
/// Conformance test logging with structured output
pub struct ConformanceTestLogger {
    test_name: String,
    spec_section: String,
    start_time: Instant,
    events: Vec<TestEvent>,
}

pub enum TestEvent {
    Phase { name: &'static str, timestamp: Duration },
    Assertion { condition: String, passed: bool, location: String },
    RuntimeEvent { description: String, details: serde_json::Value },
    Warning { message: String },
}

impl ConformanceTestLogger {
    pub fn new(test_name: &str, spec_section: &str) -> Self {
        tracing::info!(
            test = %test_name,
            spec = %spec_section,
            "╔══════════════════════════════════════════════════════════════╗"
        );
        tracing::info!(
            test = %test_name,
            "║ CONFORMANCE TEST: {}
", test_name
        );
        tracing::info!(
            spec = %spec_section,
            "║ Validates: {}
", spec_section
        );
        tracing::info!(
            "╚══════════════════════════════════════════════════════════════╝"
        );

        Self {
            test_name: test_name.to_string(),
            spec_section: spec_section.to_string(),
            start_time: Instant::now(),
            events: Vec::new(),
        }
    }

    pub fn phase(&mut self, name: &'static str) {
        let elapsed = self.start_time.elapsed();
        tracing::debug!(
            phase = %name,
            elapsed_ms = %elapsed.as_millis(),
            "▶ Entering test phase"
        );
        self.events.push(TestEvent::Phase { name, timestamp: elapsed });
    }

    pub fn assert_with_context(&mut self, condition: bool, description: &str) {
        let location = std::panic::Location::caller().to_string();
        tracing::debug!(
            condition = %description,
            passed = %condition,
            location = %location,
            "Assertion evaluated"
        );

        self.events.push(TestEvent::Assertion {
            condition: description.to_string(),
            passed: condition,
            location,
        });

        if !condition {
            tracing::error!(condition = %description, "ASSERTION FAILED");
        }

        assert!(condition, "Conformance assertion failed: {}", description);
    }

    pub fn finish(self) -> TestResult {
        let elapsed = self.start_time.elapsed();
        let passed = self.events.iter().all(|e| {
            !matches!(e, TestEvent::Assertion { passed: false, .. })
        });

        tracing::info!(
            test = %self.test_name,
            elapsed_ms = %elapsed.as_millis(),
            passed = %passed,
            "Test completed"
        );

        TestResult {
            test_name: self.test_name,
            spec_section: self.spec_section,
            duration: elapsed,
            passed,
            events: self.events,
        }
    }
}
```

